args.query:
SELECT gmap_id, name, description, num_of_reviews, "MISC"
FROM business_description
WHERE description ILIKE '%Los Angeles%' OR description ILIKE '%Los Angeles, CA%' OR description ILIKE '%Los Angeles County%' OR "MISC"::text ILIKE '%Los Angeles%' OR description ILIKE '%LA, CA%' LIMIT 500;

